import { Box, Image, Text, Button } from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

const SingleAbsolute = ({ props }) => {
  const [page, setPage] = useState("left");
  const [random, setRandom] = useState(0);

  const { onOpen, price, img } = props;

  function handlePayment() {
    onOpen();
  }

  useEffect(() => {
    setRandom((Math.random() * 20).toFixed());
  }, []);

  return (
    <Box
      bg="white"
      borderRadius="lg"
      boxShadow="lg"
      overflow="hidden"
      maxW="300px"
      transition="all 0.3s ease"
      _hover={{ transform: "translateY(-5px)", boxShadow: "xl" }}
    >
      {/* IMAGE */}
      <Image src={img} w="100%" h="160px" objectFit="cover" />

      {/* TAB */}
      <Box display="flex" fontSize="sm" fontWeight="semibold">
        <Box
          flex="1"
          textAlign="center"
          py="2"
          cursor="pointer"
          borderBottom={page === "left" ? "2px solid black" : "1px solid #eee"}
          onClick={() => setPage("left")}
        >
          Personal
        </Box>
        <Box
          flex="1"
          textAlign="center"
          py="2"
          cursor="pointer"
          borderBottom={page === "right" ? "2px solid black" : "1px solid #eee"}
          onClick={() => setPage("right")}
        >
          Teams
        </Box>
      </Box>

      {/* CONTENT */}
      <Box p={5}>
        <Text fontWeight="bold" fontSize="md" mb={2}>
          Subscribe to top courses
        </Text>

        <Text fontSize="xs" color="gray.600" mb={3}>
          Get this course + 8,000+ courses.
          <Text as="span" color="#A435F0" fontWeight="bold" ml={1}>
            Learn more
          </Text>
        </Text>

        {/* BUTTON */}
        <Button
          bg="#A435F0"
          color="white"
          w="100%"
          mb={3}
          _hover={{ bg: "#8710d8" }}
          onClick={handlePayment}
        >
          Start subscription
        </Button>

        <Box textAlign="center" fontSize="xs" color="gray.500" mb={4}>
          <Text>Starting at ₹750/month</Text>
          <Text>Cancel anytime</Text>
        </Box>

        {/* DIVIDER */}
        <Box display="flex" alignItems="center" mb={3}>
          <Box flex="1" h="1px" bg="gray.200" />
          <Text mx={2} fontSize="xs">
            or
          </Text>
          <Box flex="1" h="1px" bg="gray.200" />
        </Box>

        {/* PRICE */}
        <Box display="flex" alignItems="center" gap={2}>
          <Text fontWeight="bold">₹{price}</Text>
          <Text as="del" fontSize="sm" color="gray.500">
            ₹{((price * (+random + 100)) / 100).toFixed()}
          </Text>
          <Text fontSize="xs" color="green.600">
            {random}% off
          </Text>
        </Box>

        {/* TIME */}
        <Text fontSize="xs" color="red.500" fontWeight="bold" my={2}>
          52 minutes left at this price!
        </Text>

        {/* BUY BUTTON */}
        <Button
          variant="outline"
          w="100%"
          fontWeight="bold"
          mb={3}
          _hover={{ bg: "gray.100" }}
          onClick={handlePayment}
        >
          Buy this course
        </Button>

        {/* INFO */}
        <Box fontSize="xs" textAlign="center" color="gray.500" mb={3}>
          <Text>30-Day Money-Back Guarantee</Text>
          <Text>Full Lifetime Access</Text>
        </Box>

        {/* LINKS */}
        <Box
          display="flex"
          justifyContent="space-between"
          fontSize="xs"
          fontWeight="bold"
          color="gray.600"
        >
          <Link to="">Share</Link>
          <Link to="">Gift</Link>
          <Link to="">Coupon</Link>
        </Box>
      </Box>
    </Box>
  );
};

export default SingleAbsolute;
